    15→import { ToastContainer } from './components/Notifications';
    16→import ProtectedLayout from './components/Layout/ProtectedLayout';
    17→
    18→// Inner component that uses auth context
    19→const AppContent = () => {
    20→  const { user, loading } = useAuth();
    21→  const isAuthenticated = !!user;
    22→
    23→  if (loading) {
    24→    return (
    25→      <div className="min-h-screen flex items-center justify-center bg-gray-50">
    26→        <div className="text-center">
    27→          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mx-auto"></div>
    28→          <p className="mt-3 text-gray-600">Initializing application...</p>
    29→        </div>
    30→      </div>
    31→    );
    32→  }
    33→
    34→  return (
    35→    <Router>
    36→      <Routes>
    37→        {isAuthenticated ? (
    38→          <>
    39→            <Route path="/" element={<Navigate to="/chat" replace />} />
    40→            <Route element={<ProtectedLayout />}>
    41→              <Route path="/chat" element={<ChatPage />} />
    42→              <Route path="/dashboard" element={<Dashboard />} />
    43→              <Route path="/search" element={<PatentSearch />} />
    44→              <Route path="/graph" element={<GraphAnalysis />} />
    45→              <Route path="/analysis" element={<AnalysisWorkbench />} />
    46→              <Route path="/settings" element={<Settings />} />
    47→              <Route path="/reports" element={<Reports />} />
    48→              <Route path="/admin" element={<Admin />} />
    49→            </Route>
    50→          </>
    51→        ) : (
    52→          <>
    53→            <Route path="/" element={<LandingPage />} />
    54→            <Route path="/login" element={<Login />} />
    55→            <Route path="*" element={<Navigate to="/" replace />} />
    56→          </>
    57→        )}
    58→      </Routes>
    59→    </Router>
    60→  );
    61→};
    62→
    63→const App = () => {
    64→  return (
    65→    <AuthProvider>
    66→      <NotificationsProvider>
    67→        <AppContent />
    68→        <ToastContainer position="top-right" duration={5000} />
    69→      </NotificationsProvider>
    70→    </AuthProvider>
    71→  );
    72→}
    73→
    74→export default App;
