     1→import React, { useEffect, useState } from 'react';
     2→import { useNavigate } from 'react-router-dom';
     3→import { ChatbotProvider, useChatbot } from '../context/ChatbotContext';
     4→import Chatbot from '../components/Chatbot/Chatbot';
     5→import LimitedChat from '../components/Chatbot/LimitedChat';
     6→
     7→// Main chat page component
     8→function ChatPage() {
     9→    const { authStatus, initializeChatbot } = useChatbot();
    10→    const [isAuthChecking, setIsAuthChecking] = useState(true);
    11→    const navigate = useNavigate();
    12→
    13→    useEffect(() => {
    14→        // Simulate auth checking delay
    15→        const timer = setTimeout(() => {
    16→            setIsAuthChecking(false);
    17→        }, 1000);
    18→
    19→        return () => clearTimeout(timer);
    20→    }, []);
    21→
    22→    useEffect(() => {
    23→        // Re-initialize when auth status changes
    24→        if (authStatus.isAuthenticated && initializeChatbot) {
    25→            initializeChatbot();
    26→        }
    27→    }, [authStatus.isAuthenticated]);
    28→
    29→    if (isAuthChecking) {
    30→        return (
    31→            <div className="chat-loading d-flex justify-content-center align-items-center" style={{ height: '100vh' }}>
    32→                <div className="text-center">
    33→                    <div className="spinner-border text-primary" role="status">
    34→                        <span className="visually-hidden">Loading...</span>
    35→                    </div>
    36→                    <p className="mt-3 text-muted">Checking authentication status...</p>
    37→                </div>
    38→            </div>
    39→        );
    40→    }
    41→
    42→    // Show LimitedChat for unauthenticated users
    43→    if (!authStatus.isAuthenticated) {
    44→        return (
    45→            <LimitedChat
    46→                onGetStarted={() => {
    47→                    // Redirect to login page instead of using demo token
    48→                    navigate('/login');
    49→                }}
    50→            />
    51→        );
    52→    }
    53→
    54→    // Show full Chatbot for authenticated users
    55→    return (
    56→        <div className="chat-page h-100">
    57→            <Chatbot userId={authStatus.userId} layout="split" />
    58→        </div>
    59→    );
    60→}
    61→
    62→// Wrapper component with provider
    63→function ChatPageWithProvider() {
    64→    return (
    65→        <ChatbotProvider>
    66→            <ChatPage />
    67→        </ChatbotProvider>
    68→    );
    69→}
    70→
    71→export default ChatPageWithProvider;
    72→

