     1→import React, { useState, useEffect } from 'react';
     2→import { patentAPI } from '../api/axios';
     3→import { patentMcpAPI } from '../api/mcp';
     4→import { Search, Filter, Calendar, Building, FileText, ChevronLeft, ChevronRight, Loader2, Info, LayoutGrid, Terminal, X } from 'lucide-react';
     5→
     6→const PatentSearch = () => {
     7→    const [isAnalystMode, setIsAnalystMode] = useState(false);
     8→    const [searchParams, setSearchParams] = useState({
     9→        title: '',
    10→        abstract: '',
    11→        assignee: '',
    12→        ipc: '',
    13→        inventor: '',
    14→        status: '',
    15→        country: '',
    16→        filing_date_from: '',
    17→        filing_date_to: '',
    18→        limit: 10,
    19→        offset: 0
    20→    });
    21→    const [results, setResults] = useState([]);
    22→    const [total, setTotal] = useState(0);
    23→    const [loading, setLoading] = useState(false);
    24→    const [searched, setSearched] = useState(false);
    25→    const [metadata, setMetadata] = useState({
    26→        confidence: null,
    27→        interpretation: null,
    28→        source: null
    29→    });
    30→    const [selectedPatent, setSelectedPatent] = useState(null);
    31→    const [modalLoading, setModalLoading] = useState(false);
    32→
    33→    const handleViewDetail = async (patentId) => {
    34→        setModalLoading(true);
    35→        try {
    36→            const data = await patentAPI.get(patentId);
    37→            setSelectedPatent(data);
    38→        } catch (error) {
    39→            console.error('Failed to fetch patent detail:', error);
    40→        } finally {
    41→            setModalLoading(false);
    42→        }
    43→    };
    44→
    45→    const closeModal = () => setSelectedPatent(null);
    46→
    47→    const handleSearch = async (e) => {
    48→        if (e) e.preventDefault();
    49→        setLoading(true);
    50→        setMetadata({
    51→            confidence: null,
    52→            interpretation: null,
    53→            source: null
    54→        });
    55→        try {
    56→            // Clean up empty params
    57→            const params = Object.fromEntries(
    58→                Object.entries(searchParams).filter(([_, v]) => v !== '' && v !== null)
    59→            );
    60→
    61→            let data;
    62→            if (isAnalystMode) {
    63→                const proxyResponse = await patentMcpAPI.searchKRPatents(params);
    64→                const patentsList = Array.isArray(proxyResponse.data) ? proxyResponse.data : (proxyResponse.data.patents || []);
    65→                data = {
    66→                    patents: patentsList,
    67→                    total: proxyResponse.data.total_count || patentsList.length
    68→                };
    69→                setMetadata({
    70→                    confidence: proxyResponse.confidence,
    71→                    interpretation: proxyResponse.interpretation_note,
    72→                    source: proxyResponse.source
    73→                });
    74→            } else {
    75→                data = await patentAPI.search(params);
    76→            }
    77→
    78→            setResults(data.patents || []);
    79→            setTotal(data.total || 0);
    80→            setSearched(true);
    81→        } catch (error) {
    82→            console.error("Search failed:", error);
    83→            setResults([]);
    84→            setTotal(0);
    85→        } finally {
    86→            setLoading(false);
    87→        }
    88→    };
    89→
    90→    const handlePageChange = (newOffset) => {
    91→        setSearchParams(prev => ({ ...prev, offset: newOffset }));
