    19→                nodeIds.add(item.company);
    20→            }
    21→            if (item.competitor && !nodeIds.has(item.competitor)) {
    22→                nodes.push({ id: item.competitor, label: item.competitor, group: 'Corporation' });
    23→                nodeIds.add(item.competitor);
    24→            }
    25→            if (item.company && item.competitor) {
    26→                edges.push({ id: `e${idx}`, from: item.company, to: item.competitor });
    27→            }
    28→        });
    29→    } else if (tabType === 'problem') {
    30→        // Problem data: [{problem, solution, patent_number, title}]
    31→        data.forEach((item, idx) => {
    32→            const patentId = item.patent_number || `patent_${idx}`;
    33→            if (!nodeIds.has(patentId)) {
    34→                nodes.push({ id: patentId, label: item.title || patentId, group: 'Patent' });
    35→                nodeIds.add(patentId);
