    44→                nodes.push({ id: solutionId, label: item.solution.substring(0, 40) + '...', group: 'Technology' });
    45→                edges.push({ id: `e_sol_${idx}`, from: patentId, to: solutionId });
    46→            }
    47→        });
    48→    } else if (tabType === 'cluster') {
    49→        // Cluster data: [{technology_code, technology_level, patent_count, top_patents}]
    50→        data.forEach((item, idx) => {
    51→            const techId = item.technology_code || `tech_${idx}`;
    52→            if (!nodeIds.has(techId)) {
