    74→                }
    75→            });
    76→        });
    77→    } else if (tabType === 'network_map') {
    78→        // Network map data: {nodes: [{id, label, group}], edges: [{id, from, to, label}]}
    79→        return data;
    80→    }
    81→
    82→    return nodes.length > 0 ? { nodes, edges } : null;
    83→};
